  ('elementary-10ced7e2-moex-00961', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-110-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '關於保證之敘述，下列何者錯誤？', '["保證人之負擔較主債務人為重者，應縮減至主債務之限度", "債權人未就主債務人之財產強制執行而無效果前，且未有喪失先訴抗辯權之事由，保證人對於債權人 得拒絕清償", "主債務人所有之抗辯，保證人均得主張", "保證人對於因欠缺行為能力而無效之債務，縱使知其情事而為保證，該保證仍因從屬性而無效"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:49+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00962', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-110-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '關於不動產物權行為之敘述，下列何者錯誤？', '["要式行為", "非經登記，不生效力", "非經交付標的物，不生效力", "債權行為無效、不成立或被撤銷者，不影響不動產物權行為效力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:49+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00963', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-110-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '下列何者非屬最高限額抵押權所擔保原債權之法定確定事由？', '["擔保債權之範圍變更或因其他事由，致原債權不繼續發生者", "最高限額抵押權所擔保之債權，其請求權已因時效而消滅", "最高限額抵押權人聲請裁定拍賣抵押物", "債務人或抵押人經裁定宣告破產確定者"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:49+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00964', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-110-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '甲男乙女為夫妻，有丙、丁二子。丙有戊、己二子。丙先於甲死亡。甲死亡時，戊依法拋棄繼承。己之 應繼分為何？', '["三分之一", "四分之一", "五分之一", "六分之一"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:49+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00965', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-110-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '關於刑事訴訟法第155條第2項所定「無證據能力、未經合法調查之證據，不得作為判斷之依據。」下 列敘述何者正確？', '["這是證據之證明力的規定", "證據能力是由法院本於確信自由判斷", "這是關於嚴格證明的規定", "只要經過合法調查的證據資料，均有證據能力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:49+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00966', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-110-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '檢察官以被告甲在警詢中自白、購毒者乙在偵查中之證言等證據，起訴甲販賣毒品罪。甲在第一審受命 法官準備程序期日，陳述其在警詢時之自白，是被強暴脅迫所為，下列何人要就甲在警詢中係出於自由 意志之自白，指出證明方法？', '["甲", "檢察官", "法官", "乙"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:49+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00967', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-110-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '被告經法官訊問後，犯罪嫌疑重大，而有羈押原因，非予羈押顯難進行訴訟。然下列何項原因，不得單 獨成為羈押被告原因？', '["逃亡或有事實足認為有逃亡之虞者", "有事實足認為有湮滅、偽造、變造證據或勾串共犯或證人之虞者", "所犯為死刑、無期徒刑或最輕本刑為五年以上有期徒刑之罪者", "所犯為死刑、無期徒刑或最輕本刑為五年以上有期徒刑之罪，有相當理由認為有逃亡、湮滅、偽造、 變造證據或勾串共犯或證人之虞者"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:49+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00968', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-110-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '下列何項供述，依刑事訴訟法規定有證據能力？', '["被告在警察詢問時，依自由意志所為供述", "檢察官未為權利告知，訊問後被告所為供述", "檢察官不待被告通知之律師到場，訊問後被告所為供述", "被告於警詢被刑求取供後，隨即被移送檢察官，檢察官立刻訊問後被告所為供述"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:49+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00969', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-110-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '下列何者不屬刑法第21條第1項規定依法令之行為？', '["司法警察逮捕通緝犯", "路人甲逮捕現行犯", "父母管教滿20歲之子女", "檢察官執行死刑"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:49+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
